patch:
diff --git a/llvm/lib/Analysis/MemorySSAUpdater.cpp b/llvm/lib/Analysis/MemorySSAUpdater.cpp
index aa550f0b6a7b..72269f528928 100644
--- a/llvm/lib/Analysis/MemorySSAUpdater.cpp
+++ b/llvm/lib/Analysis/MemorySSAUpdater.cpp
@@ -1404,8 +1404,10 @@ void MemorySSAUpdater::changeToUnreachable(const Instruction *I) {
 MemoryAccess *MemorySSAUpdater::createMemoryAccessInBB(
     Instruction *I, MemoryAccess *Definition, const BasicBlock *BB,
     MemorySSA::InsertionPlace Point) {
-  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition);
-  MSSA->insertIntoListsForBlock(NewAccess, BB, Point);
+  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition, nullptr, false);
+  if (NewAccess) {
+    MSSA->insertIntoListsForBlock(NewAccess, BB, Point);
+  }
   return NewAccess;
 }

@@ -1413,9 +1415,11 @@ MemoryUseOrDef *MemorySSAUpdater::createMemoryAccessBefore(
     Instruction *I, MemoryAccess *Definition, MemoryUseOrDef *InsertPt) {
   assert(I->getParent() == InsertPt->getBlock() &&
          "New and old access must be in the same block");
-  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition);
-  MSSA->insertIntoListsBefore(NewAccess, InsertPt->getBlock(),
-                              InsertPt->getIterator());
+  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition, nullptr, false);
+  if (NewAccess) {
+    MSSA->insertIntoListsBefore(NewAccess, InsertPt->getBlock(),
+                                InsertPt->getIterator());
+  }
   return NewAccess;
 }

@@ -1423,8 +1427,10 @@ MemoryUseOrDef *MemorySSAUpdater::createMemoryAccessAfter(
     Instruction *I, MemoryAccess *Definition, MemoryAccess *InsertPt) {
   assert(I->getParent() == InsertPt->getBlock() &&
          "New and old access must be in the same block");
-  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition);
-  MSSA->insertIntoListsBefore(NewAccess, InsertPt->getBlock(),
-                              ++InsertPt->getIterator());
+  MemoryUseOrDef *NewAccess = MSSA->createDefinedAccess(I, Definition, nullptr, false);
+  if (NewAccess) {
+    MSSA->insertIntoListsBefore(NewAccess, InsertPt->getBlock(),
+                                ++InsertPt->getIterator());
+  }
   return NewAccess;
 }

